cssBlock:
:root {
  --bg: #0A0A0A;
  --bg-card: #141414;
  --bg-elevated: #1C1C1C;
  --bg-overlay: rgba(10, 10, 10, 0.88);
  --border: #2D2D2D;
  --border-strong: #3A3A3A;
  --text-primary: #F4F4F4;
  --text-bright: #FFFFFF;
  --text-muted: #9CA0A8;
  --text-subtle: #6B6E76;
  --text-disabled: #5A5D65;
  --accent: #BC6025;
  --accent-hover: #D17434;
  --accent-pressed: #9F4F1C;
  --accent-subtle: rgba(188, 96, 37, 0.12);
  --accent-glow: rgba(188, 96, 37, 0.32);
  --accent-border: rgba(188, 96, 37, 0.28);
  --success: #6A8161;
  --success-subtle: rgba(106, 129, 97, 0.14);
  --danger: #C84A2A;
  --ring: rgba(188, 96, 37, 0.55);
}
